import { React, useState } from 'react'
import Box from '@mui/material/Box'
import Button from '@mui/material/Button'
import FormControl from '@mui/material/FormControl'
import FormGroup from '@mui/material/FormGroup'
import FormHelperText from '@mui/material/FormHelperText'
import { Link, Navigate, useNavigate } from 'react-router-dom';
import useAuth from '../hooks/useAuth'
import Loading from './Loading'
import supabaseClient from '../supabase'

const Login = () => {

    const { user, session, loading, setUser } = useAuth()

    const navigate = useNavigate()

    const [error, setError ] = useState()

    const dataUser = e => {
        setUser({
            ...user,
            [e.target.name]: e.target.value
        })
    }


    const handleSubmit = async(e) => {

        e.preventDefault()

        setError('')

        try {

            await supabaseClient.auth.signInWithPassword(user.email, user.password)
            
            navigate('/')

        } catch(error) {

            if ( error.code === "auth/user-not-found")
            {
                setError('El usuario ingresado no existe.');
            } else if ( error.code === "auth/wrong-password")
            {
                setError('La contraseña no es correcta.');
            } else if ( error.code === "auth/internal-error")
            {
                setError('Se debe ingresar la contraseña.');
            } else if ( error.code === "auth/invalid-email")
            {
                setError('Se debe ingresar un mail válido.');
            } else
            {
                setError('Se produjo un error. Volvé a intentar más tarde.');
            }
                
        }
        
    }
    

  return (
        <>
        {   
            session != null ? <Navigate to="/" /> :
             loading ? <Loading /> : 

            <Box display="flex" flexDirection="column" alignItems="center" justifyContent="center" height="100vh">
                <Box width="100vw">
                    <img src="../img/trama.svg" alt='Trama de fondo'/>
                </Box>
                
                <img src="../img/logo-register-login.png" alt='Logo de Biblios'/>
                <h1>¡Hola de nuevo!</h1>
                <p>Ingresá con tu email y password.</p>
                <FormControl onSubmit={handleSubmit} className='text-center mx-4 mt-2 d-flex flex-column justify-content-between form-login'>
                            <Box >
                                <FormGroup className="mb-4 pb-4" >
                                    <FormControl className="field-register-log" type="email" placeholder="Email" name="email" onChange={dataUser} />
                                </FormGroup>

                                <FormGroup className="mb-5 input-txt" >
                                    <FormControl  className="field-register-log"  type="password" placeholder="Password" name="password" onChange={dataUser} />
                                </FormGroup>

                                {error &&
                                    <FormHelperText>
                                    <p className='invalid'> {error} </p>
                                    </FormHelperText>
                                    }

                                <FormHelperText className=''>
                                    ¿No tenés una cuenta? <Link to='/register' replace={true} className='link-login'>Registrate</Link>
                                </FormHelperText>
                            </Box>
                            <Button type="submit" className='btn-submit mb-5'>
                                Ingresar
                            </Button>
                                
                        </FormControl>
            </Box>
        
                        
}
        </>
  )
}

export default Login
